def slugify_value(value):
    value = (value or "").lower()
    value = value.replace("&", " and ")
    cleaned = []
    previous_dash = False
    for char in value:
        if char.isalnum():
            cleaned.append(char)
            previous_dash = False
        else:
            if not previous_dash:
                cleaned.append("-")
                previous_dash = True
    slug = "".join(cleaned).strip("-")
    return slug or "concept"


def sentence_case_list(items):
    cleaned = [item.strip().rstrip(".") for item in items if item and item.strip()]
    if not cleaned:
        return ""
    if len(cleaned) == 1:
        return cleaned[0]
    if len(cleaned) == 2:
        return f"{cleaned[0]} and {cleaned[1]}"
    return f"{', '.join(cleaned[:-1])}, and {cleaned[-1]}"


def first_sentence(text):
    text = (text or "").strip()
    if not text:
        return ""
    for separator in ".!?":
        index = text.find(separator)
        if index != -1:
            return text[: index + 1]
    return text


