def normalize_concept_item(concept):
    if isinstance(concept, str):
        title = concept.strip()
        return {
            "slug": slugify_value(title),
            "title": title,
            "noteUrl": "",
        }

    if not isinstance(concept, dict):
        return None

    title = (concept.get("title") or "").strip()
    if not title:
        return None

    normalized = deepcopy(concept)
    normalized["title"] = title
    normalized["slug"] = concept.get("slug") or slugify_value(title)
    normalized["noteUrl"] = concept.get("noteUrl") or ""
    return normalized


def extract_note_slug(note_url):
    if not note_url:
        return None
    parsed = urlparse(note_url)
    segments = [segment for segment in parsed.path.split("/") if segment]
    if "notes" not in segments:
        return None
    index = segments.index("notes")
    if index == len(segments) - 1:
        return None
    return segments[index + 1]


def make_note_slug(tutorial_slug, concept_slug):
    base = f"tutorial-{slugify_value(tutorial_slug)}-{slugify_value(concept_slug)}"
    return base[:240].strip("-")


