def build_markdown_note(tutorial_title, tutorial_overview, concept_title, learn_points, tutorial_slug):
    tutorial_sentence = first_sentence(tutorial_overview) or f"{tutorial_title} builds essential understanding through structured practice."
    learn_points_text = sentence_case_list(learn_points[:3])
    if learn_points_text:
        explanation_link = f"It connects directly to the broader tutorial goals of {learn_points_text.lower()}."
    else:
        explanation_link = f"It supports the wider reasoning framework used throughout {tutorial_title}."

    overview_section = (
        f"{concept_title} is a core concept inside **{tutorial_title}**. "
        f"{tutorial_sentence} This note is designed to help a learner understand the idea, apply it with confidence, "
        f"and avoid the most common reasoning mistakes. {explanation_link}"
    )

    explanation_paragraphs = [
        (
            f"Start by defining **{concept_title}** clearly and identifying the objects, variables, structures, or decisions that matter most. "
            f"In strong learning, this concept is never treated as an isolated fact; it becomes useful when you can explain *why* it exists, "
            f"*when* it should be applied, and *what* changes when the inputs or assumptions change."
        ),
        (
            f"A reliable workflow is to represent the situation first, choose the rule or process that matches **{concept_title}**, "
            f"work step by step, and then verify that the result is consistent with the context of **{tutorial_title}**. "
            f"This helps move from memorization to transferable understanding."
        ),
        (
            f"As you revise, connect **{concept_title}** to nearby ideas in the same tutorial. "
            f"That connection is what allows the concept to appear naturally in mixed problems, projects, design discussions, or interview explanations."
        ),
    ]

    key_ideas = [
        f"Define **{concept_title}** precisely before applying any rule, formula, or workflow.",
        f"Identify the standard representation of **{concept_title}** used in **{tutorial_title}**.",
        "Break the task into smaller steps so the reasoning remains visible and checkable.",
        "Test assumptions, constraints, edge cases, or hidden conditions before finalizing the answer.",
        f"Link **{concept_title}** to adjacent ideas so it becomes part of a broader problem-solving toolkit.",
    ]

    examples = tutorial_examples(tutorial_slug, concept_title)
    mistakes = tutorial_mistakes(tutorial_slug, concept_title)
    practice_prompts = tutorial_practice_prompts(tutorial_slug, concept_title, tutorial_title)

    summary_points = [
        f"**{concept_title}** matters because it strengthens how you reason inside **{tutorial_title}**.",
        "Good performance comes from combining definition, representation, method, and verification.",
        "The concept becomes durable when you can explain it, use it, and critique incorrect uses of it.",
    ]

    lines = [
        f"# {concept_title}",
        "",
        "## Overview",
        overview_section,
        "",
        "## Explanation",
    ]
    for paragraph in explanation_paragraphs:
        lines.extend([paragraph, ""])

    lines.append("## Key Ideas")
    lines.extend([f"- {item}" for item in key_ideas])
    lines.extend(["", "## Examples"])
    lines.extend([f"- {item}" for item in examples])
    lines.extend(["", "## Common Mistakes"])
    lines.extend([f"- {item}" for item in mistakes])
    lines.extend(["", "## Summary"])
    lines.extend([f"- {item}" for item in summary_points])
    lines.extend(["", "## Practice Prompts"])
    lines.extend([f"- {item}" for item in practice_prompts])
    lines.append("")
    return "\n".join(lines)


def text_content(text):
    return [{"type": "text", "text": text, "styles": {}}]


def make_block(block_type, text, props=None):
    return {
        "type": block_type,
        "props": props or {},
        "content": text_content(text),
        "children": [],
    }


def markdown_to_blocknote(markdown_text):
    blocks = []
    paragraph_lines = []
    bullet_lines = []

    def flush_paragraph():
        if paragraph_lines:
            text = " ".join(line.strip() for line in paragraph_lines if line.strip())
            if text:
                blocks.append(make_block("paragraph", text))
            paragraph_lines[:] = []

    def flush_bullets():
        if bullet_lines:
            for line in bullet_lines:
                blocks.append(make_block("bulletListItem", line))
            bullet_lines[:] = []

    for raw_line in (markdown_text or "").splitlines():
        line = raw_line.rstrip()
        stripped = line.strip()

        if not stripped:
            flush_paragraph()
            flush_bullets()
            continue

        if stripped.startswith("### "):
            flush_paragraph()
            flush_bullets()
            blocks.append(make_block("heading", stripped[4:], {"level": 3}))
            continue

        if stripped.startswith("## "):
            flush_paragraph()
            flush_bullets()
            blocks.append(make_block("heading", stripped[3:], {"level": 2}))
            continue

        if stripped.startswith("# "):
            flush_paragraph()
            flush_bullets()
            blocks.append(make_block("heading", stripped[2:], {"level": 1}))
            continue

        if stripped.startswith("- "):
            flush_paragraph()
            bullet_lines.append(stripped[2:].strip())
            continue

        flush_bullets()
        paragraph_lines.append(stripped)

    flush_paragraph()
    flush_bullets()
    return blocks


def choose_creator(User):
    for role in ("admin", "teacher"):
        user = User.objects.filter(role=role, is_active=True).order_by("id").first()
        if user:
            return user
    return User.objects.filter(is_active=True).order_by("id").first()


def note_payload(Note, creator, tutorial_slug, tutorial_title, concept, tutorial_overview, learn_points, profile_slug):
    concept_slug = concept["slug"]
    note_title = f"{concept['title']} - {tutorial_title}"
    note_slug = make_note_slug(tutorial_slug, concept_slug)
    markdown = build_markdown_note(
        tutorial_title=tutorial_title,
        tutorial_overview=tutorial_overview,
        concept_title=concept["title"],
        learn_points=learn_points,
        tutorial_slug=tutorial_slug,
    )

    payload = {
        "title": note_title,
        "slug": note_slug,
        "content": markdown_to_blocknote(markdown),
        "creator_id": creator.id,
        "note_type": "individual",
        "privacy": "public",
        "price": 0,
        "discounted_price": None,
        "access_duration_days": 0,
        "description": (
            f"Detailed study note for the core concept \"{concept['title']}\" inside {tutorial_title}. "
            f"{SEED_DESCRIPTION_MARKER}"
        ),
        "is_draft": False,
        "is_active": True,
    }

    note_fields = {field.name for field in Note._meta.get_fields() if hasattr(field, "name")}
    if "profileTypes" in note_fields:
        payload["profileTypes"] = [profile_slug]
    if "ask_ai_enabled" in note_fields:
        payload["ask_ai_enabled"] = False
    if "ask_ai_monthly_price" in note_fields:
        payload["ask_ai_monthly_price"] = 0
    return payload, markdown


def get_or_create_note(Note, creator, tutorial_slug, tutorial_title, concept, tutorial_overview, learn_points, profile_slug):
    existing_slug = extract_note_slug(concept.get("noteUrl"))
    if existing_slug:
        existing_note = Note.objects.filter(slug=existing_slug).first()
        if existing_note:
            return existing_note, False

    note_slug = make_note_slug(tutorial_slug, concept["slug"])
    existing_note = Note.objects.filter(slug=note_slug).first()
    if existing_note:
        note_fields = {field.name for field in Note._meta.get_fields() if hasattr(field, "name")}
        if (
            "profileTypes" in note_fields
            and SEED_DESCRIPTION_MARKER in (existing_note.description or "")
        ):
            current_profiles = list(getattr(existing_note, "profileTypes", []) or [])
            if profile_slug not in current_profiles:
                current_profiles.append(profile_slug)
                existing_note.profileTypes = current_profiles
                existing_note.save(update_fields=["profileTypes"])
        return existing_note, False

    if creator is None:
        return None, False

    payload, _markdown = note_payload(
        Note=Note,
        creator=creator,
        tutorial_slug=tutorial_slug,
        tutorial_title=tutorial_title,
        concept=concept,
        tutorial_overview=tutorial_overview,
        learn_points=learn_points,
        profile_slug=profile_slug,
    )
    return Note.objects.create(**payload), True


def ensure_concept_metadata(concept, tutorial_slug, tutorial_title, tutorial_overview, learn_points):
    concept.setdefault("slug", slugify_value(concept["title"]))
    note_title = f"{concept['title']} - {tutorial_title}"
    concept.setdefault("noteTitle", note_title)
    concept.setdefault(
        "noteSummary",
        (
            f"{concept['title']} is a core part of {tutorial_title}. "
            f"This note helps you understand the idea, use it correctly, and connect it to broader reasoning."
        ),
    )
    concept.setdefault(
        "notePoints",
        [
            f"Understand what {concept['title'].lower()} means before trying to apply it mechanically.",
            f"Relate {concept['title'].lower()} to the wider tutorial goal of {tutorial_title.lower()}.",
            "Use worked examples and self-checks to make the reasoning visible.",
            "Review common mistakes so the concept becomes dependable under pressure.",
            "Practice explaining the concept clearly, not just recalling steps.",
        ],
    )
    return concept


def enrich_tutorial_entry(entry, profile_slug, creator, Note):
    tutorial_slug = entry.get("slug") or slugify_value(entry.get("title") or "tutorial")
    tutorial_title = entry.get("title") or tutorial_slug.replace("-", " ").title()
    tutorial_overview = entry.get("overview") or entry.get("shortDescription") or ""
    learn_points = entry.get("learnPoints") if isinstance(entry.get("learnPoints"), list) else []

    existing_concepts = []
    seen = set()
    for raw_concept in entry.get("conceptsCovered", []) if isinstance(entry.get("conceptsCovered"), list) else []:
        normalized = normalize_concept_item(raw_concept)
        if not normalized:
            continue
        key = normalized["slug"]
        if key in seen:
            continue
        ensure_concept_metadata(normalized, tutorial_slug, tutorial_title, tutorial_overview, learn_points)
        existing_concepts.append(normalized)
        seen.add(key)

    canonical_titles = TUTORIAL_CONCEPT_LIBRARY.get(tutorial_slug) or fallback_concepts(tutorial_title)
    for title in canonical_titles:
        concept_slug = slugify_value(title)
        if concept_slug in seen:
            continue
        normalized = {
            "slug": concept_slug,
            "title": title,
            "noteUrl": "",
        }
        ensure_concept_metadata(normalized, tutorial_slug, tutorial_title, tutorial_overview, learn_points)
        existing_concepts.append(normalized)
        seen.add(concept_slug)

    changed = False
    for concept in existing_concepts:
        note, _created = get_or_create_note(
            Note=Note,
            creator=creator,
            tutorial_slug=tutorial_slug,
            tutorial_title=tutorial_title,
            concept=concept,
            tutorial_overview=tutorial_overview,
            learn_points=learn_points,
            profile_slug=profile_slug,
        )
        if note:
            note_url = make_note_url(note.slug)
            if concept.get("noteUrl") != note_url:
                concept["noteUrl"] = note_url
                changed = True

        ensure_concept_metadata(concept, tutorial_slug, tutorial_title, tutorial_overview, learn_points)

    if entry.get("conceptsCovered") != existing_concepts:
        entry["conceptsCovered"] = existing_concepts
        changed = True

    return changed


def seed_tutorial_core_concepts(apps, schema_editor):
    ProfileType = apps.get_model("lms", "ProfileType")
    Note = apps.get_model("notes", "Note")
    User = apps.get_model(*settings.AUTH_USER_MODEL.split("."))

    creator = choose_creator(User)

    for profile in ProfileType.objects.all().order_by("id"):
        home_content = deepcopy(profile.home_content or {})
        tutorials = home_content.get("tutorials")
        if not isinstance(tutorials, list) or not tutorials:
            continue

        changed = False
        for tutorial in tutorials:
            if not isinstance(tutorial, dict):
                continue

            pages = tutorial.get("pages")
            if isinstance(pages, list) and pages:
                for page in pages:
                    if isinstance(page, dict):
                        changed = enrich_tutorial_entry(page, profile.slug, creator, Note) or changed
            else:
                changed = enrich_tutorial_entry(tutorial, profile.slug, creator, Note) or changed

        if changed:
            ProfileType.objects.filter(pk=profile.pk).update(home_content=home_content)


def unseed_tutorial_core_concepts(apps, schema_editor):
    ProfileType = apps.get_model("lms", "ProfileType")
    Note = apps.get_model("notes", "Note")
    generated_note_slugs = set(
        Note.objects.filter(description__contains=SEED_DESCRIPTION_MARKER).values_list("slug", flat=True)
    )

    # Clear note links that point at migration-created slugs, but keep the concept entries.
    for profile in ProfileType.objects.all().order_by("id"):
        home_content = deepcopy(profile.home_content or {})
        tutorials = home_content.get("tutorials")
        if not isinstance(tutorials, list) or not tutorials:
            continue

        changed = False
        for tutorial in tutorials:
            if not isinstance(tutorial, dict):
                continue

            page_entries = tutorial.get("pages") if isinstance(tutorial.get("pages"), list) else [tutorial]
            for page in page_entries:
                concepts = page.get("conceptsCovered")
                if not isinstance(concepts, list):
                    continue
                for concept in concepts:
                    if not isinstance(concept, dict):
                        continue
                    note_slug = extract_note_slug(concept.get("noteUrl"))
                    if note_slug in generated_note_slugs:
                        concept["noteUrl"] = ""
                        changed = True

        if changed:
            ProfileType.objects.filter(pk=profile.pk).update(home_content=home_content)

    Note.objects.filter(
        description__contains=SEED_DESCRIPTION_MARKER,
    ).delete()


